class TradeViewController: UIViewController {
    @IBOutlet weak var stockSymbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var tradeButton: UIButton!

    override func viewDidLoad() {
        super.viewDidLoad()
        tradeButton.isEnabled = false
    }

    @IBAction func textFieldDidChange(_ sender: UITextField) {
        if let symbol = stockSymbolTextField.text, !symbol.isEmpty,
           let quantityText = quantityTextField.text, !quantityText.isEmpty {
            tradeButton.isEnabled = true
        } else {
            tradeButton.isEnabled = false
        }
    }

    @IBAction func executeTrade(_ sender: UIButton) {
        guard let symbol = stockSymbolTextField.text, let quantityText = quantityTextField.text,
              let quantity = Int(quantityText) else {
            return
        }

        let parameters: [String: Any] = [
            "symbol": symbol,
            "quantity": quantity
        ]

        AF.request("https://api.example.com/trade", method: .post, parameters: parameters, encoding: JSONEncoding.default).responseJSON { response in
            switch response.result {
            case .success(let value):
                print("Trade executed successfully: \(value)")
            case .failure(let error):
                print("Error executing trade: \(error.localizedDescription)")
            }
        }
    }
}

